SELECT country_id, alpha2_code, alpha3_code
FROM historical_country_data
WHERE year = 2000;

SELECT COUNT(DISTINCT country_id) 
FROM countries 
WHERE area > (SELECT AVG(area) FROM countries);

SELECT subdivision_id
FROM subdivisions
WHERE population < (SELECT AVG(population) FROM subdivisions);

SELECT population 
FROM geopolitical_data_history
WHERE year = 2000;

SELECT gd.geopolitical_id, al.user_id
FROM geopolitical_data gd
JOIN access_logs al ON gd.country_id = al.country_id;
